// Package airules 自動生成跨 AI 工具的配置檔
// 預設集（"all" 模式，--only 留空或填 all 即可）：
//
//	ChatGPT、Claude、Trae、通義靈碼、DeepSeek、Cursor、Gemini
//
// 擴充集（需以 --only 明確列出，或以 --only every 啟用全部）：
//
//	AGENTS.md、GitHub Copilot、Windsurf、Cline、Continue、Aider、Roo Code、CodeBuddy
//
// @ai:generated by=claude-opus-4-6 date=2026-02-27
// @ai:modified by=claude-opus-4-7 date=2026-06-15 reason=擴充至 15 個工具並引入預設集機制
package airules

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/maoxiaoyue/hypgo/pkg/manifest"
)

const autoGenMarker = "<!-- auto-generated by hyp ai-rules -->"

// defaultTargetNames "all" 模式下會生成的 7 個預設工具名稱
// 順序即為輸出順序（影響 CLI 訊息可讀性）
var defaultTargetNames = []string{
	"chatgpt", "claude", "trae", "tongyi", "deepseek", "cursor", "gemini",
}

// Options 控制生成行為
type Options struct {
	// DiffLogEnabled 是否在配置檔中包含 diff-log 指令
	DiffLogEnabled bool

	// Comment 控制要寫入哪些註釋規範（讀自 .hyp/comment.yaml）
	// 空值 = 預設（只開普通註釋）
	Comment CommentToggles
}

// CommentToggles 鏡像 pkg/config.CommentConfig，避免 airules 直接依賴 pkg/config
type CommentToggles struct {
	NormalComment bool
	AIComment     bool
	ThinkComment  bool
}

// DefaultCommentToggles 回傳預設值（與 config.DefaultCommentConfig 一致）
func DefaultCommentToggles() CommentToggles {
	return CommentToggles{NormalComment: true, AIComment: false, ThinkComment: false}
}

// Target 描述一個 AI 工具配置檔目標
type Target struct {
	Name     string
	RelPath  string
	Generate func(m *manifest.Manifest, opts Options) string
}

// AllTargets 回傳所有支援的 AI 工具配置檔目標（含預設集與擴充集）
// 順序：先 7 個預設集，再擴充集；用於 CLI --only every 與 FilterTargets 名稱查找
func AllTargets() []Target {
	return []Target{
		// 預設集（7 個）
		{Name: "chatgpt", RelPath: "CHATGPT.md", Generate: func(m *manifest.Manifest, opts Options) string { return generateChatGPTMD(m, opts) }},
		{Name: "claude", RelPath: "CLAUDE.md", Generate: func(m *manifest.Manifest, opts Options) string { return generateClaudeMD(m, opts) }},
		{Name: "trae", RelPath: filepath.Join(".trae", "rules", "project_rules.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateTraeMD(m, opts) }},
		{Name: "tongyi", RelPath: filepath.Join(".lingma", "rules", "project_rules.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateTongyiMD(m, opts) }},
		{Name: "deepseek", RelPath: "DEEPSEEK.md", Generate: func(m *manifest.Manifest, opts Options) string { return generateDeepSeekMD(m, opts) }},
		{Name: "cursor", RelPath: filepath.Join(".cursor", "rules", "hypgo.mdc"), Generate: func(m *manifest.Manifest, opts Options) string { return generateCursorMDC(m, opts) }},
		{Name: "gemini", RelPath: "GEMINI.md", Generate: func(m *manifest.Manifest, opts Options) string { return generateGeminiMD(m, opts) }},

		// 擴充集（僅在 --only 列名或 --only every 時生成）
		{Name: "agents", RelPath: "AGENTS.md", Generate: func(m *manifest.Manifest, opts Options) string { return generateAgentsMD(m, opts) }},
		{Name: "copilot", RelPath: filepath.Join(".github", "copilot-instructions.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateCopilotMD(m, opts) }},
		{Name: "windsurf", RelPath: filepath.Join(".windsurf", "rules", "hypgo.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateWindsurfMD(m, opts) }},
		{Name: "cline", RelPath: filepath.Join(".clinerules", "hypgo.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateClineMD(m, opts) }},
		{Name: "continue", RelPath: filepath.Join(".continue", "rules", "hypgo.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateContinueMD(m, opts) }},
		{Name: "aider", RelPath: "CONVENTIONS.md", Generate: func(m *manifest.Manifest, opts Options) string { return generateAiderMD(m, opts) }},
		{Name: "roo", RelPath: filepath.Join(".roo", "rules", "hypgo.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateRooMD(m, opts) }},
		{Name: "codebuddy", RelPath: filepath.Join(".codebuddy", "rules", "hypgo.md"), Generate: func(m *manifest.Manifest, opts Options) string { return generateCodeBuddyMD(m, opts) }},
	}
}

// DefaultTargets 回傳 "all" 模式下會生成的 7 個預設目標
// （ChatGPT、Claude、Trae、通義靈碼、DeepSeek、Cursor、Gemini）
func DefaultTargets() []Target {
	all := AllTargets()
	index := make(map[string]Target, len(all))
	for _, t := range all {
		index[t.Name] = t
	}
	result := make([]Target, 0, len(defaultTargetNames))
	for _, n := range defaultTargetNames {
		if t, ok := index[n]; ok {
			result = append(result, t)
		}
	}
	return result
}

// ResolveTargets 根據 --only 參數值選出目標：
//
//	""、"all"          → DefaultTargets()（7 個預設）
//	"every"、"*"       → AllTargets()（全部）
//	"name1,name2,..."  → 依名稱過濾 AllTargets()
func ResolveTargets(only string) []Target {
	key := strings.ToLower(strings.TrimSpace(only))
	switch key {
	case "", "all":
		return DefaultTargets()
	case "every", "*":
		return AllTargets()
	default:
		return FilterTargets(AllTargets(), only)
	}
}

// FilterTargets 根據名稱過濾目標。空字串回傳輸入原樣（保留為純函式語意；
// CLI 端請使用 ResolveTargets 套用「空字串 → 預設集」規則）
func FilterTargets(targets []Target, names string) []Target {
	if names == "" {
		return targets
	}
	wanted := make(map[string]bool)
	for _, n := range strings.Split(names, ",") {
		wanted[strings.ToLower(strings.TrimSpace(n))] = true
	}
	var result []Target
	for _, t := range targets {
		if wanted[strings.ToLower(t.Name)] {
			result = append(result, t)
		}
	}
	return result
}

// ResolveCleanTargets 同 ResolveTargets 但語意較寬：空字串 / "all" 也視為全部目標
// 理由：clean 操作只會刪除帶有 auto-gen marker 的檔案，掃描全部已知路徑不會誤刪
// 使用者手寫檔案（如自製的 CLAUDE.md）反正會因為沒有 marker 而被跳過
func ResolveCleanTargets(only string) []Target {
	key := strings.ToLower(strings.TrimSpace(only))
	switch key {
	case "", "all", "every", "*":
		return AllTargets()
	default:
		return FilterTargets(AllTargets(), only)
	}
}

// CleanAll 在指定目錄下移除自動生成的配置檔
// 只移除帶有 autoGenMarker 的檔案；手寫檔案保留
// 移除後若父目錄變空，會一併清掉（不會越過 dir 邊界）
func CleanAll(dir string, targets []Target, dryRun bool) ([]Result, error) {
	var results []Result
	for _, t := range targets {
		path := filepath.Join(dir, t.RelPath)
		info, err := os.Stat(path)
		if err != nil {
			results = append(results, Result{Path: path, Status: StatusSkipped, Message: "not found"})
			continue
		}
		if info.IsDir() {
			results = append(results, Result{Path: path, Status: StatusSkipped, Message: "is a directory"})
			continue
		}
		if !canOverwrite(path) {
			results = append(results, Result{Path: path, Status: StatusSkipped, Message: "no auto-gen marker (manual edit)"})
			continue
		}
		if dryRun {
			results = append(results, Result{Path: path, Status: StatusDryRun})
			continue
		}
		if err := os.Remove(path); err != nil {
			results = append(results, Result{Path: path, Status: StatusError, Message: err.Error()})
			continue
		}
		removeEmptyParents(filepath.Dir(path), dir)
		results = append(results, Result{Path: path, Status: StatusRemoved})
	}
	return results, nil
}

// removeEmptyParents 從 start 往上移除空目錄，但絕不刪除 stop（專案根）或更外層
func removeEmptyParents(start, stop string) {
	cur := start
	for {
		rel, err := filepath.Rel(stop, cur)
		if err != nil || rel == "." || rel == "" || strings.HasPrefix(rel, "..") {
			return
		}
		entries, err := os.ReadDir(cur)
		if err != nil || len(entries) > 0 {
			return
		}
		if err := os.Remove(cur); err != nil {
			return
		}
		cur = filepath.Dir(cur)
	}
}

// GenerateAll 在指定目錄下生成所有配置檔
func GenerateAll(dir string, targets []Target, m *manifest.Manifest, opts Options, dryRun bool) ([]Result, error) {
	var results []Result
	for _, t := range targets {
		path := filepath.Join(dir, t.RelPath)
		content := t.Generate(m, opts)

		if !canOverwrite(path) {
			results = append(results, Result{Path: path, Status: StatusSkipped, Message: "file exists without auto-gen marker"})
			continue
		}
		if dryRun {
			results = append(results, Result{Path: path, Status: StatusDryRun, Content: content})
			continue
		}
		if err := writeFile(path, content); err != nil {
			results = append(results, Result{Path: path, Status: StatusError, Message: err.Error()})
			continue
		}
		results = append(results, Result{Path: path, Status: StatusCreated})
	}
	return results, nil
}

// Result 描述單一檔案的生成結果
type Result struct {
	Path    string
	Status  Status
	Message string
	Content string
}

// Status 生成結果狀態
type Status int

const (
	StatusCreated Status = iota
	StatusSkipped
	StatusDryRun
	StatusError
	StatusRemoved
)

func (s Status) String() string {
	switch s {
	case StatusCreated:
		return "created"
	case StatusSkipped:
		return "skipped"
	case StatusDryRun:
		return "dry-run"
	case StatusError:
		return "error"
	case StatusRemoved:
		return "removed"
	default:
		return "unknown"
	}
}

func canOverwrite(path string) bool {
	data, err := os.ReadFile(path)
	if err != nil {
		return true
	}
	return strings.Contains(string(data), autoGenMarker)
}

func writeFile(path string, content string) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return fmt.Errorf("mkdir %s: %w", dir, err)
	}
	return os.WriteFile(path, []byte(content), 0644)
}
